-- =====================================================
-- 2. Структурированные критерии перехода knee_cartilage_repair
--    (JOIN на rehab_phases по program_type+phase_number → реальный phase_id)
-- =====================================================
WITH criteria_data (
  phase_number, criterion_code, label, criterion_type,
  measurement_type, measurement_source,
  threshold_operator, threshold_value, threshold_value2,
  staleness_days, self_report_question, self_report_hint,
  position, is_required
) AS (VALUES
  -- Фаза 1 → Фаза 2 (защита трансплантата → переход и подвижность)
  (1, 'flexion_brace_range',  'Сгибание колена достигло разрешённого врачом диапазона (ориентир — до 45°)', 'measurement',      'knee_flexion_degrees'::varchar, 'rom'::varchar, '>='::varchar, 45::numeric, NULL::numeric, 14::smallint, NULL::text, NULL::text, 10::smallint, TRUE),
  (1, 'wb_progress_protocol', 'Опора на ногу увеличивается по плану врача без боли и нарастания отёка',      'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 20::smallint, TRUE),
  (1, 'effusion_controlled',  'Куратор подтвердил: отёк под контролем, признаков несостоятельности нет',     'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 30::smallint, TRUE),
  -- Фаза 2 → Фаза 3 (переход и подвижность → сила и функция)
  (2, 'full_weight_bearing',  'Полная опора на ногу без боли и отёка (по плану врача)',                      'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 10::smallint, TRUE),
  (2, 'full_flexion',         'Колено сгибается в полном объёме',                                            'measurement',      'knee_flexion_degrees', 'rom', '>=', 120::numeric, NULL, 14::smallint, NULL, NULL, 20::smallint, TRUE),
  (2, 'full_extension',       'Колено полностью разгибается',                                                'measurement',      'knee_extension_degrees', 'rom', '<=', 0::numeric, NULL, 14::smallint, NULL, NULL, 30::smallint, TRUE),
  (2, 'gait_symmetric',       'Ровная, симметричная походка без хромоты (оценка куратора)',                  'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 40::smallint, TRUE),
  (2, 'no_pain_full_load',    'Нет боли и отёка при полной опоре на ногу',                                   'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Можете полностью опираться на ногу без боли и отёка?', 'Оцените за последние несколько дней', 50::smallint, TRUE),
  -- Фаза 3 → Фаза 4 (сила и функция → возврат к спорту)
  (3, 'quad_strength_90',     'Сила мышц бедра близка к здоровой ноге (ориентир — не менее 90% от здоровой стороны)', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 10::smallint, TRUE),
  (3, 'time_for_impact',      'Прошёл достаточный срок от операции для беговой нагрузки (определяет врач по виду операции)', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 20::smallint, TRUE),
  (3, 'pain_controlled_load', 'Куратор подтвердил контроль боли и отёка при функциональной нагрузке',        'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 30::smallint, TRUE),
  -- Фаза 4 → выпуск (возврат к спорту) — критерии достижения готовности, финальная фаза
  (4, 'quad_strength_rts',    'Сила ноги не менее 90% от здоровой стороны (тесты готовности к спорту)',       'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 10::smallint, TRUE),
  (4, 'hop_tests_90',         'Прыжковые тесты не менее 90% от здоровой стороны',                            'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 20::smallint, TRUE),
  (4, 'no_pain_sport_load',   'Нет боли и отёка на спорт-нагрузке',                                          'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Нет боли и отёка после спортивной нагрузки?', 'Оцените реакцию колена на тренировки', 30::smallint, TRUE),
  (4, 'full_rom_rts',         'Полный объём движений в колене',                                              'measurement',      'knee_flexion_degrees', 'rom', '>=', 120::numeric, NULL, 30::smallint, NULL, NULL, 40::smallint, TRUE),
  (4, 'functional_tests',     'Тесты на координацию, ловкость и функцию пройдены (очная оценка куратора)',    'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 50::smallint, TRUE),
  (4, 'time_for_sport',       'Достигнут минимальный срок от операции до спорта (определяет врач по виду операции)', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 60::smallint, TRUE),
  (4, 'psych_readiness',      'Чувствуете психологическую готовность вернуться к спорту',                    'self_report',      NULL, NULL, NULL, NULL, NULL, 30::smallint, 'Чувствуете уверенность и готовность вернуться к спорту?', 'Готовность в голове важна не меньше силы', 70::smallint, FALSE)
)
INSERT INTO phase_transition_criteria (
  phase_id, criterion_code, label, criterion_type,
  measurement_type, measurement_source,
  threshold_operator, threshold_value, threshold_value2, staleness_days,
  self_report_question, self_report_hint,
  position, is_required, is_active
)
SELECT
  p.id, cd.criterion_code, cd.label, cd.criterion_type,
  cd.measurement_type, cd.measurement_source,
  cd.threshold_operator, cd.threshold_value, cd.threshold_value2, cd.staleness_days,
  cd.self_report_question, cd.self_report_hint,
  cd.position, cd.is_required, TRUE
FROM criteria_data cd
JOIN rehab_phases p ON p.program_type = 'knee_cartilage_repair' AND p.phase_number = cd.phase_number
ON CONFLICT (phase_id, criterion_code) DO NOTHING;

COMMIT;
